```R
order <- c(1, 1, 1, 1)
dose <- c(100, 50, 100, 50)

is_all_ones <- all(order == 1)

if (is_all_ones) {
  unique_dose <- unique(dose)
  print(unique_dose)
} else {
  print("The order variable does not contain all values equal to 1.")
}
```

